import{_ as o,o as p,c as l,a0 as i}from"./chunks/framework.r0TJpsHX.js";const d=JSON.parse('{"title":"О переговорах","description":"","frontmatter":{"title":"О переговорах","date":"2022-03-06T00:00:00.000Z"},"headers":[],"relativePath":"posts/2022-03-06-negotiations.md","filePath":"posts/2022-03-06-negotiations.md"}'),e={name:"posts/2022-03-06-negotiations.md"};function a(s,t,n,r,_,u){return p(),l("div",null,[...t[0]||(t[0]=[i('<p>Переговоры это самый сложный вид коммуникации.</p><p>Чтобы переговоры состоялись, необходимым условием является наличие у сторон общего интереса.</p><p>Общепринятая теория психологии переговоров гласит что существует пять стратегий, пять путей выхода из конфликта, пять сильных надёжных позиций в переговорах.</p><ol><li>Черепаха.</li></ol><p>&quot;Мне нужно время чтобы подумать/собраться с мыслями/обсудить детали с коллегами/выпить стакан воды&quot;</p><p>Черепаха никогда не принимает решения.</p><p>Эта стратегия применяется когда нужно тянуть время. Когда происходит давление, когда решение ещё не принято и интересы сторон неясны.</p><ol start="2"><li>Лиса.</li></ol><p>&quot;Мы так много для вас сделали, не могли бы вы нам немного помочь&quot;.</p><p>Эту стратегию лучше всего применять когда позиция чуточку слабее, это путь уступок с нагрузкой. Согласие с условием.</p><p>Лиса никогда не бывает прямой. Всегда говорит Мы вместо Я. Лиса не слышит &quot;нет&quot;.</p><ol start="3"><li>Сова.</li></ol><p>&quot;Учитывая все нюансы и риски, ради общей пользы я предлагаю обсудить все возможные решения и выбрать наилучшее&quot;</p><p>Сова сфокусирована на пользе и сотрудничестве. Применять следует тогда когда ситуация предельно ясна и проработана в деталях. Экспертная позиция, рациональная аргументация.</p><ol start="4"><li>Плюшевый мишка.</li></ol><p>&quot;Вы правы, мне не следовало этого делать, я совершил ошибку и очень сильно раскаиваюсь. Простите меня.&quot;</p><p>Применяется в наиболее слабой позиции, когда нужно вызвать симпатию, эмпатию, желаение обнять и пожалеть чтобы избежать санкций и неблагоприятной ситуации даже ценой собственных интересов.</p><ol start="5"><li>Акула.</li></ol><p>&quot;Ситуация очень критическая. Это недопустимое поведение и если так будет продолжаться, я буду ходатайствовать о применении соответствующих санкций в отношении всех пречисленных в отчете лиц&quot;</p><p>Применяется очень дозированно в ситуации когда позиция явно сильнее, сроки поджимают и ситуация критическая. Акула даёт оценку ситуации и делает это тоном злой учительницы ясно и четко выговаривая каждую фразу.</p><p>Несколько важных замечаний:</p><ul><li>встать и уйти стандартная реакция в ходе сложных переговоров, но это провал</li><li>эмоции вообще - враг в любых переговорах, как хорошие так и плохие</li><li>решение задачи не должно являться целью переговоров, цель переговоров - согласие сторон</li><li>то, что вы делаете в точке перехода хода меняет ход переговоров гораздо круче того что вы выражаете вербально</li></ul>',22)])])}const q=o(e,[["render",a]]);export{d as __pageData,q as default};
